# TaskFlow pattern - same pipeline, half the code
from airflow.decorators import dag, task
from datetime import datetime

@dag(schedule='@daily', start_date=datetime(2026, 1, 1), catchup=False)
def taskflow_meter_pipeline():

    @task
    def extract_meters(ds_nodash=None):
        file_path = f"s3://nordgrid-raw/meters/{ds_nodash}.csv"
        return {'file_path': file_path, 'row_count': 1_200_000}

    @task
    def validate_meters(metadata: dict):
        if metadata['row_count'] < 100_000:
            raise ValueError(f"Row count below threshold for {metadata['file_path']}")
        return metadata['file_path']

    @task
    def load_to_silver(validated_path: str):
        print(f"Loading {validated_path} to silver layer")

    metadata = extract_meters()
    path = validate_meters(metadata)
    load_to_silver(path)

taskflow_meter_pipeline()

