from airflow.decorators import dag, task, task_group
from datetime import datetime

@dag(schedule='@daily', start_date=datetime(2026, 1, 1), catchup=False)
def nordgrid_silver_pipeline():

    @task_group(group_id='quality_gates')
    def quality_gates(bronze_paths: dict):
        """Validate all Bronze sources before transformation."""

        @task
        def validate_meters(path: str) -> dict:
            count = count_rows(path)
            return {'source': 'meters', 'rows': count, 'passed': count > 100_000}

        @task
        def validate_scada(path: str) -> dict:
            count = count_rows(path)
            return {'source': 'scada', 'rows': count, 'passed': count > 50_000}

        @task
        def validate_weather(path: str) -> dict:
            count = count_rows(path)
            return {'source': 'weather', 'rows': count, 'passed': count > 1_000}

        @task
        def aggregate_results(meter_r: dict, scada_r: dict, weather_r: dict) -> bool:
            all_passed = all([meter_r['passed'], scada_r['passed'], weather_r['passed']])
            if not all_passed:
                raise ValueError('Quality gate failed')
            return True

        m = validate_meters(bronze_paths['meters'])
        s = validate_scada(bronze_paths['scada'])
        w = validate_weather(bronze_paths['weather'])
        return aggregate_results(m, s, w)

    @task
    def extract_bronze_paths(ds_nodash=None) -> dict:
        return {
            'meters': f's3://bronze/meters/{ds_nodash}/',
            'scada': f's3://bronze/scada/{ds_nodash}/',
            'weather': f's3://bronze/weather/{ds_nodash}/'
        }

    @task
    def transform_to_silver(gate_passed: bool, ds_nodash=None):
        if gate_passed:
            print(f'Transforming data for {ds_nodash} to Silver')

    paths = extract_bronze_paths()
    gate_result = quality_gates(paths)
    transform_to_silver(gate_result)

nordgrid_silver_pipeline()

from airflow.exceptions import AirflowSkipException

@task
def process_region(region: str, ds_nodash=None):
    path = f's3://bronze/meters/{region}/{ds_nodash}.csv'
    if not file_exists(path):
        raise AirflowSkipException(f'No data for {region} on {ds_nodash} - skipping')
    return process(path)

from typing import TypedDict

class MeterExtractionResult(TypedDict):
    file_path: str
    row_count: int
    null_pct: float
    checksum: str
    extract_ts: str

@task(multiple_outputs=True)
def extract_meters(ds_nodash: str = None) -> MeterExtractionResult:
    file_path = f"s3://nordgrid-raw/meters/{ds_nodash}.csv"
    return MeterExtractionResult(
        file_path=file_path,
        row_count=1_200_000,
        null_pct=0.02,
        checksum='abc123',
        extract_ts='2026-03-15T06:12:34Z'
    )

@task
def validate_meters(file_path: str, row_count: int, null_pct: float) -> str:
    if row_count < 100_000:
        raise ValueError(f'Too few rows: {row_count}')
    if null_pct > 0.05:
        raise ValueError(f'Null percentage too high: {null_pct}')
    return file_path

